import { Router, Request, Response } from "express";
import { ExecutionStatus, getFullnodeUrl, IotaClient, IotaTransactionBlockResponse } from "@iota/iota-sdk/client";
import { Ed25519Keypair } from "@iota/iota-sdk/keypairs/ed25519";
import { getObject } from "./utils/getObject";
import { ObjectEdge, searchObjectsByType } from "./utils/searchObjectByType";
import { Arguments, Transaction, TransactionArgument } from "@iota/iota-sdk/transactions";
import { gasStationCfg, singAndExecTx } from "./utils/signAndExecTx";
// Import Move bindings generated by your Move-to-JS tool


const router = Router();

//--- Inizializzazione delle costanti e variabili globali ---
let creditToken: string;
let policy: string;
let controllerCap: string;
let OIDcontrollerCap: string;
let defaultPackageID: string;
let client: IotaClient;
let seed: string;
let keyPair: Ed25519Keypair;
let network: string;
let configuration_object: string;
let graphqlProvider: string;
let gasStation: gasStationCfg = {
  gasStation1URL: "https://gas1.objectid.io",
  gasStation1Token: "1111",
  gasStation2URL: "https://gas2.objectid.io",
  gasStation2Token: "1111",
};
let useGasStation = false;
let tokenCreditType: string;
let policyTokenType: string;

/**
 * Inizializza il client IOTA, le costanti Move e le variabili d'ambiente.
 */
async function init() {
  seed = process.env.SEED || "88f389b6a8806a3207778b31d73b6aacca06d6cadcf84d5a6c533ae53d250852";
  network = process.env.NETWORK || "testnet";
  configuration_object =
    process.env.CONFIGURATION_OBJECT || "0x8b8a88963245733f4109b3277ee4691790d178c1be5261f9272e63c1cf184f88";
  graphqlProvider = process.env.GRAPHQL_PROVIDER || "https://graphql.testnet.iota.cafe/";

  creditToken = "0x19ff793c834e52ba313e5bffe8bd5231ae6593bfdf6143fc4c65a5e140d3a539";
  controllerCap = "0xfd0c97bb8e7053cf893248cd95d56458d1e12dd1842b53ca8baa96e4a9617d17";
  OIDcontrollerCap = "0x5fc756968a4577949fe24839b750b397b08f6e323d7da6f3e2ed706a8c2798f2";

  client = new IotaClient({ url: getFullnodeUrl(network) });
  keyPair = Ed25519Keypair.deriveKeypairFromSeed(seed);

  const onchainCfgObject = (await getObject(client, configuration_object)) as any;

  if (!onchainCfgObject || !onchainCfgObject.content || !onchainCfgObject.content.fields) {
    throw new Error("Invalid configuration object received from the blockchain");
  }

  defaultPackageID = onchainCfgObject.content.fields.official_packages[0];

  tokenCreditType = `0x2::token::Token<${defaultPackageID}::oid_credit::OID_CREDIT>`;
  policyTokenType = `0x2::token::TokenPolicy<${defaultPackageID}::oid_credit::OID_CREDIT>`;

  const pedges: ObjectEdge[] = await searchObjectsByType(policyTokenType, graphqlProvider);

  policy = pedges[0].node.address;

  console.log("defaultPackageID", defaultPackageID);
  console.log("credit token", creditToken);
  console.log("OIDcontrollerCap", OIDcontrollerCap);
  console.log("Private key:", keyPair.getSecretKey());
  console.log("address:", keyPair.toIotaAddress());
}

init();


router.post("/create_object", async (req: Request, res: Response) => {
  try {
    const { object_type, product_url, description, op_code, immutable_metadata, mutable_metadata, geo_location } =
      req.body;

    const tx = new Transaction();
    const moveFunction = defaultPackageID + "::oid_object::create_object";

    console.log("==============================================================")
    console.log(" create_object")
    console.log("==============================================================")
    console.log("creditToken: ", creditToken)
    console.log("policy: ", policy)
    console.log("OIDcontrollerCap: ", OIDcontrollerCap)
    console.log("object_type: ", object_type)
    console.log("product_url: ", product_url)
    console.log("op_code: ", op_code)
    console.log("JSON.stringify(immutable_metadata): ", JSON.stringify(immutable_metadata))
    console.log("JSON.stringify(mutable_metadata): ", JSON.stringify(mutable_metadata))
    console.log("geo_location: ", geo_location)

    tx.moveCall({
      arguments: [
        tx.object(creditToken),
        tx.object(policy),
        tx.object(OIDcontrollerCap),
        tx.pure.string(object_type),
        tx.pure.string(product_url),
        tx.pure.string(description),
        tx.pure.string(op_code),
        tx.pure.string(JSON.stringify(immutable_metadata)),
        tx.pure.string(JSON.stringify(mutable_metadata)),
        tx.pure.string(geo_location),
        tx.object("0x6"),
      ],
      target: moveFunction,
    });
    
    const sender = keyPair.toIotaAddress();
    tx.setGasBudget(10000000);
    tx.setSender(sender);

    singAndExecTx(
      network,
      client,
      gasStation,
      useGasStation,
      keyPair,
      tx,
      {

        onSuccess: (result: IotaTransactionBlockResponse) => {         
          
          const status = result.effects?.status as ExecutionStatus
          const txDigest= result.digest

          if (status.status == "success") {

            const newObjectId =    result.effects?.created?.[0]?.reference?.objectId;

            res.json({ success: true, txDigest, newObjectId});
            console.log("Success, txDigest: ", txDigest, newObjectId);
          } else {
            res.json({ success: false, txDigest , error: status.error });
            console.error("Object creation failed.");
          }
        },
        onError: (err: any) => {
          res.json({ success: false, undefined , error: undefined });
          console.error("Object creation failed:", err);
        },
        onSettled: () => {
        },
      },
    );
  } catch (err) {
    console.error("Unexpected error:", err);
  }
});

router.post("/update_object_mutable_metadata", async (req: Request, res: Response) => {
  try {
    const { object, new_mutable_metadata } =
      req.body;

    const tx = new Transaction();
    const moveFunction = defaultPackageID + "::oid_object::update_object_mutable_metadata";

    console.log("==============================================================")
    console.log(" update_object_mutable_metadata ")
    console.log("==============================================================")
    console.log("creditToken: ", creditToken)
    console.log("policy: ", policy)
    console.log("OIDcontrollerCap: ", OIDcontrollerCap)
    console.log("object: ", object)
    console.log("new_mutable_metadata: ", new_mutable_metadata)

    tx.moveCall({
      arguments: [
        tx.object(creditToken),
        tx.object(policy),
        tx.object(controllerCap),
        tx.object(object),
        tx.pure.string(new_mutable_metadata),
      ],
      target: moveFunction,
    });
    
    const sender = keyPair.toIotaAddress();
    tx.setGasBudget(10000000);
    tx.setSender(sender);

    singAndExecTx(
      network,
      client,
      gasStation,
      useGasStation,
      keyPair,
      tx,
      {
        onSuccess: (result: IotaTransactionBlockResponse) => {

          const status = result.effects?.status as ExecutionStatus
          const txDigest= result.digest

          if (status.status == "success") {
            res.json({ success: true, txDigest });
            console.log("Success, txDigest: ", txDigest);
          } else {
            res.json({ success: false, txDigest , error: status.error });
            console.error("Object creation failed.");
          }
        },
        onError: (err: any) => {
          res.json({ success: false, undefined , error: undefined });
          console.error("Object creation failed:", err);
        },
        onSettled: () => {
        },
      },
    );
  } catch (err) {
    console.error("Unexpected error:", err);
  }
});






router.stack.forEach((r: any) => {
  if (r.route && r.route.path) {
    console.log(`✅ Route attiva: ${r.route.path}`);
  } else if (r.name === 'router') {
    console.log('➡️ Sub-router o middleware attivo');
  } else {
    console.log('❓ Entry non riconosciuta nello stack:', r);
  }
});

export default router;
